package pi

import (
	"irrlicht/core/pkg/tailer"
)

// Parser implements tailer.TranscriptParser for Pi coding agent transcripts.
// Pi nests role, stopReason, content, and usage inside a "message" object:
//
//	{"type": "message", "message": {"role": "assistant", "stopReason": "stop", ...}}
type Parser struct{}

// ParseLine parses a Pi JSONL line into a normalized ParsedEvent.
func (p *Parser) ParseLine(raw map[string]interface{}) *tailer.ParsedEvent {
	ev := &tailer.ParsedEvent{
		Timestamp: tailer.ParseTimestamp(raw),
	}

	eventType := ""
	if et, ok := raw["type"].(string); ok {
		eventType = et
	}

	// No type field → skip (shouldn't happen for Pi but be defensive).
	if eventType == "" {
		ev.Skip = true
		return ev
	}

	// Session header: {"type": "session", "version": 3, "cwd": "..."}
	if eventType == "session" {
		if cwd, ok := raw["cwd"].(string); ok && cwd != "" {
			ev.CWD = cwd
		}
		ev.Skip = true
		return ev
	}

	// Model change — extract model info and skip.
	if eventType == "model_change" {
		if model, ok := raw["modelId"].(string); ok && model != "" {
			ev.ModelName = tailer.NormalizeModelName(model)
		}
		ev.Skip = true
		return ev
	}

	// Non-message metadata types — skip.
	switch eventType {
	case "thinking_level_change", "compaction", "branch_summary", "custom":
		ev.Skip = true
		return ev
	}

	// All remaining Pi events should be type: "message" with a nested message object.
	if eventType != "message" {
		ev.Skip = true
		return ev
	}

	piMsg, ok := raw["message"].(map[string]interface{})
	if !ok {
		ev.Skip = true
		return ev
	}

	role, _ := piMsg["role"].(string)

	switch role {
	case "assistant":
		stopReason, _ := piMsg["stopReason"].(string)
		if stopReason == "stop" {
			ev.EventType = "assistant_message" // end-of-turn
		} else {
			ev.EventType = "assistant" // mid-turn (toolUse, etc.)
		}

		// Extract tool calls from message.content[].
		if contentArr, ok := piMsg["content"].([]interface{}); ok {
			for _, item := range contentArr {
				if block, ok := item.(map[string]interface{}); ok {
					if block["type"] == "toolCall" {
						if name, ok := block["name"].(string); ok {
							ev.ToolUseNames = append(ev.ToolUseNames, name)
						}
					}
				}
			}
		}

		// Extract assistant text for waiting-state display.
		ev.AssistantText = extractPiAssistantText(piMsg)

		// Model and tokens from the message.
		if model, ok := piMsg["model"].(string); ok && model != "" {
			ev.ModelName = tailer.NormalizeModelName(model)
		}
		if usage, ok := piMsg["usage"].(map[string]interface{}); ok {
			ev.Tokens = tailer.ExtractUsage(usage)
		}

	case "user":
		ev.EventType = "user_message"
		ev.ClearToolNames = true

	case "toolResult":
		ev.EventType = "tool_result"
		ev.ToolResultCount = 1 // Single canonical count — NOT also counted in addMessageEvent.
		if isErr, ok := piMsg["isError"].(bool); ok && isErr {
			ev.IsError = true
		}

	case "bashExecution":
		// User-side shell escape (! command) — skip.
		ev.Skip = true
		return ev

	default:
		ev.Skip = true
		return ev
	}

	// Content character count.
	ev.ContentChars = tailer.ExtractContentChars(raw)

	return ev
}

// extractPiAssistantText extracts text from Pi's nested message.content[] blocks.
func extractPiAssistantText(piMsg map[string]interface{}) string {
	contentArr, ok := piMsg["content"].([]interface{})
	if !ok {
		return ""
	}
	var text string
	for _, item := range contentArr {
		if block, ok := item.(map[string]interface{}); ok {
			if block["type"] == "text" {
				if t, ok := block["text"].(string); ok && t != "" {
					text = t // Use the last text block.
				}
			}
		}
	}
	if len([]rune(text)) > 200 {
		return string([]rune(text)[:200])
	}
	return text
}

// StateClassifier provides pure functions for session state classification.
// These functions encapsulate the four-way decision tree used to determine
// whether a session is working, waiting, or ready based on transcript metrics.
package services

import (
	"fmt"

	"irrlicht/core/domain/session"
)

// ClassifyState applies the four-way decision tree to determine what state a
// session should be in based on its current state and latest metrics.
//
// Decision order:
//  1. NeedsUserAttention → waiting
//  2. IsAgentDone → ready (from working/waiting only)
//  3. ESC cancellation (user + error + no open tools) → ready
//  4. Default → working
//
// Returns (newState, reason). An empty reason means no transition occurred.
func ClassifyState(currentState string, metrics *session.SessionMetrics) (string, string) {
	if metrics == nil {
		return currentState, ""
	}

	// 1. User-blocking tool open → waiting.
	if metrics.NeedsUserAttention() {
		if currentState != session.StateWaiting {
			return session.StateWaiting, "user-blocking tool open → waiting"
		}
		return currentState, ""
	}

	// 2. Agent finished turn — check if waiting for user input first.
	if metrics.IsAgentDone() {
		// 2a. Turn ended with a question → waiting (agent needs user input).
		if metrics.IsWaitingForUserInput() {
			if currentState != session.StateWaiting {
				return session.StateWaiting, "turn ended with question → waiting"
			}
			return currentState, ""
		}
		// 2b. Normal turn completion → ready.
		if currentState == session.StateWorking || currentState == session.StateWaiting {
			return session.StateReady, "agent finished turn → ready"
		}
		return currentState, ""
	}

	// 3. ESC cancellation: user event with is_error=true while working/waiting
	// with no open tool calls → ready.
	if (currentState == session.StateWorking || currentState == session.StateWaiting) &&
		!metrics.HasOpenToolCall && metrics.LastEventType == "user" && metrics.LastToolResultWasError {
		return session.StateReady,
			fmt.Sprintf("rejected tool result while %s → ready (cancellation)", currentState)
	}

	// 4. Default: transcript activity → working.
	if currentState != session.StateWorking {
		return session.StateWorking,
			fmt.Sprintf("transcript activity (%s → working)", currentState)
	}

	return currentState, ""
}

// InferSubagents detects in-process sub-agent activity from open Agent tool
// calls. Claude Code Explore/Plan agents run inside the parent process and
// don't create separate transcripts, so open Agent tool calls are the only
// detection path. Returns nil if no Agent tools are open.
func InferSubagents(metrics *session.SessionMetrics) *session.SubagentSummary {
	if metrics == nil || !metrics.HasOpenToolCall {
		return nil
	}
	agentCount := 0
	for _, name := range metrics.LastOpenToolNames {
		if name == "Agent" {
			agentCount++
		}
	}
	if agentCount == 0 {
		return nil
	}
	return &session.SubagentSummary{
		Total:   agentCount,
		Working: agentCount,
	}
}

package session

import (
	"time"
)

// State constants — three MECE states for session lifecycle.
// See STATES.md for the formal state machine specification.
const (
	StateWorking = "working" // Agent actively processing (tools, text generation, hooks, compaction)
	StateWaiting = "waiting" // Agent finished turn, waiting for user input
	StateReady   = "ready"   // Session inactive (process exited, transcript removed, cancelled)

	CompactionStateNotCompacting = "not_compacting"
	CompactionStateCompacting    = "compacting"
	CompactionStatePostCompact   = "post_compact"
)

// SessionMetrics holds computed performance metrics from transcript analysis.
type SessionMetrics struct {
	ElapsedSeconds     int64   `json:"elapsed_seconds"`
	TotalTokens        int64   `json:"total_tokens"`
	ModelName          string  `json:"model_name"`
	ContextWindow      int64   `json:"context_window,omitempty"`
	ContextUtilization float64 `json:"context_utilization_percentage"`
	PressureLevel      string  `json:"pressure_level"`

	// Tool call tracking — count unmatched tool_use/tool_result pairs.
	HasOpenToolCall   bool `json:"has_open_tool_call"`
	OpenToolCallCount int  `json:"open_tool_call_count,omitempty"`

	// LastEventType is the type of the most recent transcript event
	// (e.g. "assistant", "user", "tool_use", "tool_result").
	LastEventType string `json:"last_event_type,omitempty"`

	// LastOpenToolNames holds tool names from the most recent assistant
	// message that called tools. Used to detect user-blocking tools.
	LastOpenToolNames []string `json:"last_open_tool_names,omitempty"`

	// LastToolResultWasError is true when the most recent tool_result had
	// is_error=true (user rejection via ESC). Distinguishes cancellation
	// from normal tool completion.
	LastToolResultWasError bool `json:"last_tool_result_was_error"`

	// EstimatedCostUSD is the estimated session cost in USD, computed from
	// token breakdown and per-model pricing.
	EstimatedCostUSD float64 `json:"estimated_cost_usd,omitempty"`

	// LastCWD is the most recent working directory extracted from the
	// transcript during metrics parsing. Used to avoid a separate file read.
	LastCWD string `json:"-"` // transient — not persisted in session JSON

	// LastAssistantText is the text content of the most recent assistant
	// message, truncated to ~200 characters. Used to surface the question
	// or request when the session is in the waiting state.
	LastAssistantText string `json:"last_assistant_text,omitempty"`

	// PermissionMode is the session's permission mode from the JSONL
	// (e.g. "default", "plan", "bypassPermissions"). Used to skip the
	// stale-tool-call timer when permissions are bypassed.
	PermissionMode string `json:"permission_mode,omitempty"`
}

// NeedsUserAttention returns true when a user-blocking tool is open — one
// that always requires user input regardless of permission settings.
// Most tools auto-execute (Bash, Read, Write, Agent, MCP, etc.) and should
// NOT trigger a waiting state; only explicit user-interaction tools do.
func (m *SessionMetrics) NeedsUserAttention() bool {
	if m == nil || !m.HasOpenToolCall {
		return false
	}
	for _, name := range m.LastOpenToolNames {
		if isUserBlockingTool(name) {
			return true
		}
	}
	return false
}

// isUserBlockingTool returns true for tools that always block for user input,
// regardless of permission settings. These are the only tools that should
// trigger the "waiting" state.
func isUserBlockingTool(name string) bool {
	return name == "AskUserQuestion" || name == "ExitPlanMode"
}

// IsWaitingForUserInput returns true when the agent finished its turn but the
// last assistant message ends with a question mark — indicating the agent is
// waiting for user input even though no user-blocking tool is open.
func (m *SessionMetrics) IsWaitingForUserInput() bool {
	if m == nil || m.LastAssistantText == "" {
		return false
	}
	// LastAssistantText is already trimmed by the tailer.
	return m.LastAssistantText[len(m.LastAssistantText)-1] == '?'
}

// IsAgentDone returns true when the agent finished its turn. The primary
// signal is Claude Code's "turn_duration" system event which fires exactly
// once at the end of each turn. Legacy formats (Codex) fall back to the
// heuristic of "last event is assistant and no open tool calls".
//
// Open tool calls (e.g. the Agent tool waiting for a sub-agent) override
// turn_done: the turn isn't truly complete until all tool results arrive.
func (m *SessionMetrics) IsAgentDone() bool {
	if m == nil {
		return false
	}
	// Open tool calls mean the agent is still processing — a sub-agent
	// spawned via the Agent tool fires turn_done before the tool result
	// comes back, but the session is NOT idle.
	if m.HasOpenToolCall {
		return false
	}
	// Primary: Claude Code writes a system/turn_duration event at end of turn.
	if m.LastEventType == "turn_done" {
		return true
	}
	// Fallback: some transcripts lack turn_duration/stop_hook_summary entirely.
	// Claude Code uses "assistant", Codex uses "assistant_message"/"assistant_output".
	// Safe because HasOpenToolCall is checked first — mid-turn tool calls block this.
	// Note: Claude Code intermediate/streaming messages use "assistant_streaming"
	// which is NOT matched here, preventing false positives between tool calls.
	switch m.LastEventType {
	case "assistant", "assistant_message", "assistant_output":
		return true
	}
	return false
}

// SubagentSummary tracks the aggregate state of all child sessions.
type SubagentSummary struct {
	Total   int `json:"total"`
	Working int `json:"working"`
	Waiting int `json:"waiting"`
	Ready   int `json:"ready"`
}

// SessionState represents the current state of a Claude Code or Copilot session.
type SessionState struct {
	Version         int             `json:"version"`
	SessionID       string          `json:"session_id"`
	State           string          `json:"state"`
	// Adapter identifies the source agent (e.g. "claude-code", "codex").
	// Empty means Claude Code (for backwards compatibility).
	Adapter string `json:"adapter,omitempty"`
	CompactionState string          `json:"compaction_state,omitempty"`
	Model           string          `json:"model,omitempty"`
	CWD             string          `json:"cwd,omitempty"`
	TranscriptPath  string          `json:"transcript_path,omitempty"`
	GitBranch       string          `json:"git_branch,omitempty"`
	ProjectName     string          `json:"project_name,omitempty"`
	FirstSeen       int64           `json:"first_seen"`
	UpdatedAt       int64           `json:"updated_at"`
	Confidence      string          `json:"confidence"`
	EventCount      int             `json:"event_count"`
	LastEvent       string          `json:"last_event"`
	LastMatcher     string          `json:"last_matcher,omitempty"`
	Metrics         *SessionMetrics `json:"metrics,omitempty"`

	// PID of the Claude Code process that owns this session (set on SessionStart).
	PID int `json:"pid,omitempty"`

	// ParentSessionID links a subagent session to its spawning parent session.
	// Derived from file path or heuristic matching in SessionDetector.
	ParentSessionID string `json:"parent_session_id,omitempty"`

	// Subagents holds the aggregate state of all child sessions.
	// Nil when this session has no children.
	Subagents *SubagentSummary `json:"subagents,omitempty"`

	// DaemonVersion records which irrlichd version created this session,
	// enabling future data migrations when the schema evolves.
	DaemonVersion string `json:"daemon_version,omitempty"`

	// Transcript monitoring for waiting-state recovery.
	LastTranscriptSize int64  `json:"last_transcript_size,omitempty"`
	WaitingStartTime   *int64 `json:"waiting_start_time,omitempty"`
}

// IsStale reports whether the session's last update is older than maxAge.
// A zero or negative maxAge disables the check (always returns false).
func (s *SessionState) IsStale(maxAge time.Duration) bool {
	if maxAge <= 0 {
		return false
	}
	return time.Since(time.Unix(s.UpdatedAt, 0)) > maxAge
}

// StringState returns a display-friendly state string including compaction state.
func (s *SessionState) StringState() string {
	if s.CompactionState != "" && s.CompactionState != CompactionStateNotCompacting {
		return s.State + "(" + s.CompactionState + ")"
	}
	return s.State
}

// MergeMetrics merges new metrics with old, preserving old values when new are zero/empty.
func MergeMetrics(newM, oldM *SessionMetrics) *SessionMetrics {
	if newM == nil {
		return oldM
	}
	if oldM == nil {
		return newM
	}
	merged := &SessionMetrics{
		ElapsedSeconds:     newM.ElapsedSeconds,
		TotalTokens:        newM.TotalTokens,
		ModelName:          newM.ModelName,
		ContextWindow:      newM.ContextWindow,
		ContextUtilization: newM.ContextUtilization,
		PressureLevel:      newM.PressureLevel,
		HasOpenToolCall:    newM.HasOpenToolCall,
		OpenToolCallCount:  newM.OpenToolCallCount,
		LastEventType:          newM.LastEventType,
		LastOpenToolNames:      newM.LastOpenToolNames,
		LastToolResultWasError: newM.LastToolResultWasError,
		EstimatedCostUSD:       newM.EstimatedCostUSD,
		LastAssistantText:      newM.LastAssistantText,
		PermissionMode:         newM.PermissionMode,
	}
	if merged.ContextWindow == 0 && oldM.ContextWindow > 0 {
		merged.ContextWindow = oldM.ContextWindow
	}
	if merged.ElapsedSeconds == 0 && oldM.ElapsedSeconds > 0 {
		merged.ElapsedSeconds = oldM.ElapsedSeconds
	}
	if merged.TotalTokens == 0 && oldM.TotalTokens > 0 {
		merged.TotalTokens = oldM.TotalTokens
	}
	if (merged.ModelName == "" || merged.ModelName == "unknown") && oldM.ModelName != "" && oldM.ModelName != "unknown" {
		merged.ModelName = oldM.ModelName
	}
	if merged.ContextUtilization == 0 && oldM.ContextUtilization > 0 {
		merged.ContextUtilization = oldM.ContextUtilization
	}
	if (merged.PressureLevel == "" || merged.PressureLevel == "unknown") && oldM.PressureLevel != "" && oldM.PressureLevel != "unknown" {
		merged.PressureLevel = oldM.PressureLevel
	}
	if merged.EstimatedCostUSD == 0 && oldM.EstimatedCostUSD > 0 {
		merged.EstimatedCostUSD = oldM.EstimatedCostUSD
	}
	if merged.PermissionMode == "" && oldM.PermissionMode != "" {
		merged.PermissionMode = oldM.PermissionMode
	}
	return merged
}

package tailer

import (
	"bufio"
	"encoding/json"
	"fmt"
	"io"
	"os"
	"path/filepath"
	"strings"
	"time"

	"irrlicht/core/pkg/capacity"
)

// MessageEvent represents a single message event from transcript
type MessageEvent struct {
	Timestamp time.Time `json:"timestamp"`
	EventType string    `json:"event_type"`
	Content   string    `json:"content,omitempty"`
}

// SessionMetrics holds computed performance metrics
type SessionMetrics struct {
	MessagesPerMinute float64        `json:"messages_per_minute"`
	ElapsedSeconds    int64          `json:"elapsed_seconds"`
	LastMessageAt     time.Time      `json:"last_message_at"`
	MessageHistory    []MessageEvent `json:"-"` // Sliding window, not serialized
	SessionStartAt    time.Time      `json:"session_start_at"`
	TotalTokens       int64          `json:"total_tokens,omitempty"`
	InputTokens       int64          `json:"input_tokens,omitempty"`
	OutputTokens      int64          `json:"output_tokens,omitempty"`
	CacheReadTokens   int64          `json:"cache_read_tokens,omitempty"`
	CacheCreationTokens int64        `json:"cache_creation_tokens,omitempty"`
	EstimatedCostUSD  float64        `json:"estimated_cost_usd,omitempty"`
	ModelName         string         `json:"model_name,omitempty"`
	ContextWindow     int64          `json:"context_window,omitempty"`
	ContextUtilization float64       `json:"context_utilization_percentage,omitempty"`
	PressureLevel     string         `json:"pressure_level,omitempty"` // "safe", "caution", "warning", "critical"

	// Raw event data for real-time client-side calculations
	TotalEventCount        int64     `json:"total_event_count,omitempty"`
	RecentEventCount       int64     `json:"recent_event_count,omitempty"`
	RecentEventWindowStart time.Time `json:"recent_event_window_start,omitempty"`

	// Tool call tracking — count unmatched tool_use/tool_result pairs
	HasOpenToolCall   bool `json:"has_open_tool_call"`
	OpenToolCallCount int  `json:"open_tool_call_count,omitempty"`

	// LastEventType is the event type of the most recent message event in
	// the transcript (e.g. "assistant", "user", "tool_use", "tool_result").
	// Used for content-based working/waiting detection.
	LastEventType string `json:"last_event_type,omitempty"`

	// LastOpenToolNames holds the tool names from the most recent assistant
	// message that called tools. Cleared when a user message appears.
	// Used to detect user-blocking tools (AskUserQuestion, ExitPlanMode).
	LastOpenToolNames []string `json:"last_open_tool_names,omitempty"`

	// LastToolResultWasError is true when the most recently processed
	// tool_result content block had is_error=true (user rejection / ESC).
	LastToolResultWasError bool `json:"last_tool_result_was_error"`

	// LastCWD is the most recent working directory seen in the transcript.
	// Extracted during parsing so callers don't need a separate file read.
	LastCWD string `json:"last_cwd,omitempty"`

	// LastAssistantText is the text content of the most recent assistant
	// message, truncated to ~200 characters.
	LastAssistantText string `json:"last_assistant_text,omitempty"`

	// PermissionMode is the session's permission mode (e.g. "default",
	// "plan", "bypassPermissions"). Extracted from "permission-mode" events.
	PermissionMode string `json:"permission_mode,omitempty"`
}

// TranscriptTailer monitors transcript files and computes metrics.
// Format-specific parsing is delegated to a TranscriptParser.
type TranscriptTailer struct {
	path        string
	lastOffset  int64
	metrics     *SessionMetrics
	windowSize  time.Duration // Default 60 seconds
	capacityMgr *capacity.CapacityManager

	// parser handles format-specific line parsing (Claude Code, Codex, Pi).
	parser TranscriptParser

	// adapter name for model config fallback.
	adapter string

	// Context window override from transcript or extended context model suffix.
	contextWindowOverride int64

	// Tool call pairing counters — accumulated from ParsedEvent deltas.
	toolUseCount    int
	toolResultCount int

	// lastOpenToolNames holds tool names from open tool calls.
	lastOpenToolNames []string

	// contentChars accumulates character count from message content for
	// token estimation when explicit token counts aren't available.
	contentChars int64

	// Token breakdown accumulators (latest snapshot, not cumulative).
	inputTokens         int64
	outputTokens        int64
	cacheReadTokens     int64
	cacheCreationTokens int64

	// lastToolResultWasError tracks is_error on the most recent tool_result.
	lastToolResultWasError bool

	// lastCWD tracks the most recent working directory seen in transcript lines.
	lastCWD string

	// lastAssistantText holds the text content of the most recent assistant
	// message, truncated to ~200 characters.
	lastAssistantText string
}

// NewTranscriptTailer creates a new tailer for the given transcript path.
// The parser handles format-specific line parsing; adapter is used for model
// config fallback.
func NewTranscriptTailer(path string, parser TranscriptParser, adapter string) *TranscriptTailer {
	return &TranscriptTailer{
		path:        path,
		lastOffset:  0,
		capacityMgr: capacity.DefaultCapacityManager(),
		parser:      parser,
		adapter:     adapter,
		metrics: &SessionMetrics{
			MessageHistory: make([]MessageEvent, 0),
			SessionStartAt: time.Time{},
		},
		windowSize: 60 * time.Second,
	}
}

// SetSessionStartTime allows preserving the session start time across multiple invocations
func (t *TranscriptTailer) SetSessionStartTime(startTime time.Time) {
	if t.metrics != nil {
		t.metrics.SessionStartAt = startTime
	}
}

// TailAndProcess reads the last ~64KB of transcript and processes new entries
func (t *TranscriptTailer) TailAndProcess() (*SessionMetrics, error) {
	file, err := os.Open(t.path)
	if err != nil {
		return nil, fmt.Errorf("failed to open transcript: %w", err)
	}
	defer file.Close()

	stat, err := file.Stat()
	if err != nil {
		return nil, fmt.Errorf("failed to stat transcript: %w", err)
	}
	fileSize := stat.Size()

	const maxTailSize = 64 * 1024
	startPos := int64(0)
	if fileSize > maxTailSize {
		startPos = fileSize - maxTailSize
	}
	if t.lastOffset > startPos {
		startPos = t.lastOffset
	}

	_, err = file.Seek(startPos, io.SeekStart)
	if err != nil {
		return nil, fmt.Errorf("failed to seek transcript: %w", err)
	}

	scanner := bufio.NewScanner(file)
	currentOffset := startPos

	for scanner.Scan() {
		line := strings.TrimSpace(scanner.Text())
		currentOffset += int64(len(scanner.Bytes()) + 1)

		if line == "" {
			continue
		}

		// Quick JSON check.
		if !strings.HasPrefix(line, "{") || !strings.HasSuffix(line, "}") {
			continue
		}

		var raw map[string]interface{}
		if err := json.Unmarshal([]byte(line), &raw); err != nil {
			continue
		}

		// Delegate to format-specific parser.
		parsed := t.parser.ParseLine(raw)
		if parsed == nil || parsed.Skip {
			// Even for skipped events, apply metadata that the parser extracted
			// (e.g. model from model_change, CWD from session header).
			if parsed != nil {
				t.applyMetadata(parsed)
			}
			continue
		}

		// Apply tool tracking deltas from the parser.
		t.toolUseCount += len(parsed.ToolUseNames)
		t.lastOpenToolNames = append(t.lastOpenToolNames, parsed.ToolUseNames...)
		t.toolResultCount += parsed.ToolResultCount
		for i := 0; i < parsed.ToolResultCount; i++ {
			if len(t.lastOpenToolNames) > 0 {
				t.lastOpenToolNames = t.lastOpenToolNames[1:]
			}
		}
		if parsed.ClearToolNames && parsed.ToolResultCount == 0 {
			t.lastOpenToolNames = nil
		}
		if parsed.IsError {
			t.lastToolResultWasError = true
		} else if parsed.ToolResultCount > 0 {
			t.lastToolResultWasError = false
		}

		// Apply metadata.
		t.applyMetadata(parsed)

		// Track assistant text.
		if parsed.AssistantText != "" {
			t.lastAssistantText = parsed.AssistantText
		}
		if parsed.ClearToolNames {
			t.lastAssistantText = ""
		}

		// Accumulate content chars.
		t.contentChars += parsed.ContentChars

		t.addMessageEvent(MessageEvent{
			Timestamp: parsed.Timestamp,
			EventType: parsed.EventType,
		})
	}

	t.lastOffset = currentOffset

	// Compute current metrics.
	t.computeMetrics()

	// Model config fallback.
	if t.metrics.ModelName == "" {
		if defaultModel := getDefaultModelFromConfig(t.adapter); defaultModel != "" {
			t.metrics.ModelName = defaultModel
		}
	}

	// Estimate tokens from content chars when no explicit token data exists.
	if t.metrics.TotalTokens == 0 && t.contentChars > 0 && t.capacityMgr != nil && t.metrics.ModelName != "" {
		cap := t.capacityMgr.GetModelCapacity(t.metrics.ModelName)
		ratio := cap.CharToTokenRatio
		if ratio <= 0 {
			ratio = 4.0
		}
		t.metrics.TotalTokens = int64(float64(t.contentChars) / ratio)
		if t.inputTokens == 0 && t.outputTokens == 0 {
			t.inputTokens = t.metrics.TotalTokens * 9 / 10
			t.outputTokens = t.metrics.TotalTokens - t.inputTokens
		}
	}

	// Recompute cost if token estimation filled in the breakdown.
	if t.metrics.EstimatedCostUSD == 0 && t.inputTokens > 0 && t.capacityMgr != nil && t.metrics.ModelName != "" {
		t.metrics.InputTokens = t.inputTokens
		t.metrics.OutputTokens = t.outputTokens
		t.metrics.EstimatedCostUSD = t.capacityMgr.EstimateCostUSD(
			t.metrics.ModelName, t.inputTokens, t.outputTokens, t.cacheReadTokens, t.cacheCreationTokens)
	}

	t.computeContextUtilization()

	return t.metrics, scanner.Err()
