// Package inbound defines inbound port interfaces — contracts that inbound
// adapters (file watchers, HTTP handlers, etc.) satisfy to drive the
// application core.
package inbound

import (
	"context"

	"irrlicht/core/domain/agent"
	"irrlicht/core/domain/orchestrator"
)

// AgentWatcher watches a directory tree for agent transcript file changes,
// emitting events for new sessions, activity, and removals. Each
// implementation targets a specific agent (Claude Code, Codex, etc.).
type AgentWatcher interface {
	// Watch begins watching for transcript changes. It blocks until ctx is
	// cancelled or an unrecoverable error occurs.
	Watch(ctx context.Context) error
	// Subscribe returns a channel that receives agent events.
	Subscribe() <-chan agent.Event
	// Unsubscribe removes a previously subscribed channel and closes it.
	Unsubscribe(ch <-chan agent.Event)
}

// OrchestratorWatcher monitors a multi-agent orchestration system and
// produces standardised state snapshots. Each implementation targets a
// specific orchestrator (Gas Town, etc.).
type OrchestratorWatcher interface {
	// Name returns the orchestrator identifier (e.g. "gastown").
	Name() string
	// Detected returns true if the orchestrator is installed/available.
	Detected() bool
	// Watch begins monitoring and blocks until ctx is cancelled.
	Watch(ctx context.Context) error
	// Subscribe returns a channel of orchestrator state snapshots.
	Subscribe() <-chan orchestrator.State
	// Unsubscribe removes a subscriber channel.
	Unsubscribe(ch <-chan orchestrator.State)
	// State returns the latest state snapshot, or nil if unavailable.
	State() *orchestrator.State
}

// Package agent defines domain types for coding agent transcript file events.
package agent

// EventType classifies transcript file-system events.
type EventType string

const (
	// EventNewSession fires when a new .jsonl transcript file appears.
	EventNewSession EventType = "new_session"
	// EventActivity fires when an existing .jsonl transcript file is written to.
	EventActivity EventType = "activity"
	// EventRemoved fires when a .jsonl transcript file is deleted.
	EventRemoved EventType = "removed"
)

// Event carries information about a single agent transcript change.
type Event struct {
	Type           EventType
	Adapter        string // Source adapter name (e.g. "claude-code", "codex")
	SessionID      string // UUID portion of the filename (without .jsonl)
	ProjectDir     string // Leaf directory name under the watched root
	TranscriptPath string // Absolute path to the .jsonl file
	Size           int64  // Current file size in bytes (0 for removals)
	CWD            string // Working directory of the agent process (set by process scanner)
}

package metrics

import (
	"sync"

	"irrlicht/core/adapters/inbound/agents/claudecode"
	"irrlicht/core/adapters/inbound/agents/codex"
	"irrlicht/core/adapters/inbound/agents/pi"
	"irrlicht/core/domain/session"
	"irrlicht/core/pkg/tailer"
)

// lockedTailer wraps a TranscriptTailer with its own mutex so that
// concurrent ComputeMetrics calls for different sessions don't block
// each other — only calls for the same transcript path serialize.
type lockedTailer struct {
	mu sync.Mutex
	t  *tailer.TranscriptTailer
}

// Adapter implements ports/outbound.MetricsCollector using the transcript-tailer package.
// It caches TranscriptTailer instances per path so that lastOffset-based
// incremental reads work across calls, avoiding re-parsing the full 64KB tail.
type Adapter struct {
	mu      sync.Mutex // protects the map only
	tailers map[string]*lockedTailer
}

// New returns a new metrics Adapter.
func New() *Adapter {
	return &Adapter{tailers: make(map[string]*lockedTailer)}
}

// parserFor returns the format-specific TranscriptParser for the given adapter name.
func parserFor(adapter string) tailer.TranscriptParser {
	switch adapter {
	case codex.AdapterName:
		return &codex.Parser{}
	case pi.AdapterName:
		return &pi.Parser{}
	default:
		return &claudecode.Parser{}
	}
}

// ComputeMetrics analyses the transcript at transcriptPath and returns session metrics.
// The adapter parameter selects the correct transcript parser.
// Returns (nil, nil) when the transcript doesn't exist yet or yields no data.
func (a *Adapter) ComputeMetrics(transcriptPath, adapter string) (*session.SessionMetrics, error) {
	if transcriptPath == "" {
		return nil, nil
	}
	a.mu.Lock()
	lt, ok := a.tailers[transcriptPath]
	if !ok {
		lt = &lockedTailer{t: tailer.NewTranscriptTailer(transcriptPath, parserFor(adapter), adapter)}
		a.tailers[transcriptPath] = lt
	}
	a.mu.Unlock()

	// Per-tailer lock: serializes calls for the same path but allows
	// different sessions to process concurrently.
	lt.mu.Lock()
	m, err := lt.t.TailAndProcess()
	lt.mu.Unlock()
	if err != nil || m == nil {
		return nil, nil //nolint:nilerr — absent transcript is not an error
	}
	result := &session.SessionMetrics{
		ElapsedSeconds:         m.ElapsedSeconds,
		TotalTokens:            m.TotalTokens,
		ModelName:              m.ModelName,
		ContextWindow:          m.ContextWindow,
		ContextUtilization:     m.ContextUtilization,
		PressureLevel:          m.PressureLevel,
		HasOpenToolCall:        m.HasOpenToolCall,
		OpenToolCallCount:      m.OpenToolCallCount,
		LastEventType:          m.LastEventType,
		LastOpenToolNames:      m.LastOpenToolNames,
		LastToolResultWasError: m.LastToolResultWasError,
		EstimatedCostUSD:       m.EstimatedCostUSD,
		LastCWD:                m.LastCWD,
		LastAssistantText:      m.LastAssistantText,
		PermissionMode:         m.PermissionMode,
	}
	if result.ModelName == "" {
		result.ModelName = "unknown"
	}
	if result.PressureLevel == "" {
		result.PressureLevel = "unknown"
	}
	return result, nil
}

// Package tailer provides transcript tailing and metrics computation.
// Format-specific parsing is delegated to TranscriptParser implementations
// that live in each agent adapter package.
package tailer

import (
	"regexp"
	"strings"
	"time"
)

// ParsedEvent is the normalized output from a format-specific transcript parser.
// Each parser maps its native event structure into these fields.
type ParsedEvent struct {
	EventType string    // normalized: "assistant_message", "user_message", "turn_done", etc.
	Timestamp time.Time // event timestamp
	Skip      bool      // true → ignore this line entirely

	// Tool tracking — parser reports deltas, tailer accumulates.
	ToolUseNames    []string // tool names from tool_use/toolCall blocks in this event
	ToolResultCount int      // number of tool_result blocks in this event
	IsError         bool     // true if the tool result had is_error=true
	ClearToolNames  bool     // true → reset lastOpenToolNames (on user messages)

	// Metadata extracted by the parser.
	ModelName      string
	ContextWindow  int64
	Tokens         *TokenSnapshot // nil = no token data in this event
	AssistantText  string         // ≤200 chars, for waiting-state display
	ContentChars   int64          // character count for token estimation
	CWD            string         // working directory if found
	PermissionMode string         // Claude Code only
}

// TokenSnapshot holds a token breakdown from a single event.
type TokenSnapshot struct {
	Input         int64
	Output        int64
	CacheRead     int64
	CacheCreation int64
	Total         int64
}

// TranscriptParser parses a single JSONL line from a specific transcript format
// and returns a normalized ParsedEvent. Implementations live in each agent
// adapter package (claudecode, codex, pi).
type TranscriptParser interface {
	// ParseLine parses a raw JSON map and returns a normalized event.
	// Returns nil for lines that should be silently ignored (no event emitted).
	ParseLine(raw map[string]interface{}) *ParsedEvent
}

// --- Shared helpers used by multiple parsers ---

// NormalizeModelName normalizes model names by removing date suffixes, extended
// context markers, and handling aliases. Exported for use by adapter parsers.
func NormalizeModelName(rawModel string) string {
	if rawModel == "" {
		return ""
	}

	// Strip extended context suffix (e.g. "claude-opus-4-6[1m]")
	rawModel = strings.TrimSuffix(rawModel, "[1m]")

	// Handle common aliases first
	aliases := map[string]string{
		"opusplan": "claude-opus-4-1",
		"sonnet":   "claude-sonnet-4-6",
		"haiku":    "claude-haiku-4-5",
	}
	if normalized, exists := aliases[rawModel]; exists {
		return normalized
	}

	// Remove date suffixes (e.g., "claude-opus-4-6-20250715" -> "claude-opus-4-6")
	datePattern := regexp.MustCompile(`-\d{8}$`)
	normalized := datePattern.ReplaceAllString(rawModel, "")

	// Match most-specific patterns first (longer model IDs before shorter)
	switch {
	case strings.Contains(normalized, "claude-opus-4-6"):
		return "claude-opus-4-6"
	case strings.Contains(normalized, "claude-sonnet-4-6"):
		return "claude-sonnet-4-6"
	case strings.Contains(normalized, "claude-sonnet-4-5"):
		return "claude-sonnet-4-5"
	case strings.Contains(normalized, "claude-haiku-4-5"):
		return "claude-haiku-4-5"
	case strings.Contains(normalized, "claude-opus-4-1"):
		return "claude-opus-4-1"
	case strings.Contains(normalized, "claude-sonnet-4"):
		return "claude-4-sonnet"
	case strings.Contains(normalized, "claude-3.5-sonnet"):
		return "claude-3.5-sonnet"
	case strings.Contains(normalized, "claude-3.5-haiku"):
		return "claude-3.5-haiku"
	}
	return normalized
}

// ExtractAssistantText extracts and concatenates text blocks from an assistant
// message, returning at most 200 characters. Checks both Claude Code
// (message.content[].text) and Codex (content[].text / content[].output_text) formats.
func ExtractAssistantText(raw map[string]interface{}) string {
	var parts []string

	collectText := func(arr []interface{}) {
		for _, item := range arr {
			if block, ok := item.(map[string]interface{}); ok {
				bt := block["type"]
				if bt == "text" || bt == "output_text" {
					if text, ok := block["text"].(string); ok && text != "" {
						parts = append(parts, text)
					}
				}
			}
		}
	}

	// Claude Code: message.content[]
	if msg, ok := raw["message"].(map[string]interface{}); ok {
		if arr, ok := msg["content"].([]interface{}); ok {
			collectText(arr)
		}
	}
	// Codex: top-level content[]
	if arr, ok := raw["content"].([]interface{}); ok {
		collectText(arr)
	}

	var text string
	switch len(parts) {
	case 0:
		return ""
	case 1:
		text = strings.TrimSpace(parts[0])
	default:
		text = strings.TrimSpace(strings.Join(parts, " "))
	}

	runes := []rune(text)
	if len(runes) > 200 {
		return string(runes[:200])
	}
	return text
}

// ExtractContentChars returns the total character count of text content in
// a transcript event, checking common content locations across formats.
func ExtractContentChars(raw map[string]interface{}) int64 {
	var chars int64
	// Top-level content array (Codex newer format)
	if arr, ok := raw["content"].([]interface{}); ok {
		for _, item := range arr {
			if block, ok := item.(map[string]interface{}); ok {
				if text, ok := block["text"].(string); ok {
					chars += int64(len(text))
				}
			}
		}
	}
	// Nested message.content array (Claude Code format)
	if msg, ok := raw["message"].(map[string]interface{}); ok {
		if arr, ok := msg["content"].([]interface{}); ok {
			for _, item := range arr {
				if block, ok := item.(map[string]interface{}); ok {
					if text, ok := block["text"].(string); ok {
						chars += int64(len(text))
					}
				}
			}
		}
	}
	// Codex function_call arguments
	if args, ok := raw["arguments"].(string); ok {
		chars += int64(len(args))
	}
	// Codex function_call_output
	if output, ok := raw["output"].(string); ok {
		chars += int64(len(output))
	}
	return chars
}

// ExtractUsage pulls token breakdown fields from a usage map.
// Handles both standard (Claude/Codex) and Pi field naming conventions.
func ExtractUsage(usage map[string]interface{}) *TokenSnapshot {
	snap := &TokenSnapshot{}
	hasBreakdown := false

	if v, ok := usage["input_tokens"].(float64); ok {
		snap.Input = int64(v)
		hasBreakdown = true
	}
	if v, ok := usage["output_tokens"].(float64); ok {
		snap.Output = int64(v)
		hasBreakdown = true
	}
	// Pi uses shorter field names as fallback.
	if !hasBreakdown {
		if v, ok := usage["input"].(float64); ok {
			snap.Input = int64(v)
			hasBreakdown = true
		}
		if v, ok := usage["output"].(float64); ok {
			snap.Output = int64(v)
			hasBreakdown = true
		}
	}
	// Standard cache field names.
	if v, ok := usage["cache_read_input_tokens"].(float64); ok {
		snap.CacheRead = int64(v)
	}
	if v, ok := usage["cache_creation_input_tokens"].(float64); ok {
		snap.CacheCreation = int64(v)
	}
	// Pi cache field names.
	if v, ok := usage["cacheRead"].(float64); ok {
		snap.CacheRead = int64(v)
	}
	if v, ok := usage["cacheWrite"].(float64); ok {
		snap.CacheCreation = int64(v)
	}
	snap.Total = snap.Input + snap.Output + snap.CacheRead + snap.CacheCreation
	// total_tokens override
	if total, ok := usage["total_tokens"].(float64); ok {
		snap.Total = int64(total)
	}
	// Pi totalTokens field.
	if total, ok := usage["totalTokens"].(float64); ok {
		snap.Total = int64(total)
	}

	if !hasBreakdown && snap.Total == 0 {
		return nil
	}
	return snap
}

// ParseTimestamp extracts a timestamp from a raw JSON map, trying RFC3339
// and millisecond-precision formats, then numeric Unix timestamps.
func ParseTimestamp(raw map[string]interface{}) time.Time {
	if ts, ok := raw["timestamp"]; ok {
		if tsStr, ok := ts.(string); ok {
			if parsed, err := time.Parse(time.RFC3339, tsStr); err == nil {
				return parsed
			}
			if parsed, err := time.Parse("2006-01-02T15:04:05.000Z", tsStr); err == nil {
				return parsed
			}
		} else if tsNum, ok := ts.(float64); ok && tsNum > 0 {
			return time.Unix(int64(tsNum), 0)
		}
	}
	return time.Now()
}

