	}
	if newState.PID != 42 {
		t.Errorf("new session PID: got %d, want 42", newState.PID)
	}
}

func TestIsAgentDone(t *testing.T) {
	tests := []struct {
		name    string
		metrics *session.SessionMetrics
		want    bool
	}{
		{"nil metrics", nil, false},
		{"turn_done", &session.SessionMetrics{LastEventType: "turn_done"}, true},
