package capacity

import (
	"encoding/json"
	"fmt"
	"io"
	"os"
	"strings"
	"sync"
	"time"
)

// ModelPricing holds per-token pricing in USD per million tokens.
type ModelPricing struct {
	InputPerMTok         float64 `json:"input_per_mtok"`
	OutputPerMTok        float64 `json:"output_per_mtok"`
	CacheReadPerMTok     float64 `json:"cache_read_per_mtok"`
	CacheCreationPerMTok float64 `json:"cache_creation_per_mtok"`
}

// ModelCapacity represents the capacity configuration for a specific model
type ModelCapacity struct {
	ContextWindow    int64             `json:"context_window"`
	MaxOutput        int64             `json:"max_output"`
	CharToTokenRatio float64           `json:"char_to_token_ratio"`
	Family           string            `json:"family"`
	DisplayName      string            `json:"display_name"`
	Notes            string            `json:"notes,omitempty"`
	BetaFeatures     map[string]int64  `json:"beta_features,omitempty"`
	Pricing          *ModelPricing     `json:"pricing,omitempty"`
}

// CapacityConfig represents the entire model capacity configuration
type CapacityConfig struct {
	Version        string                    `json:"version"`
	LastUpdated    string                    `json:"last_updated"`
	Models         map[string]ModelCapacity  `json:"models"`
	FamilyDefaults map[string]ModelCapacity  `json:"family_defaults"`
	Fallback       ModelCapacity             `json:"fallback"`
	EstimationNotes map[string]string        `json:"estimation_notes"`
}

// CapacityManager handles model capacity loading and caching
type CapacityManager struct {
	config     *CapacityConfig
	configPath string
	lastModified time.Time
	mu         sync.RWMutex
}

// TokenEstimation represents estimated or actual token usage
type TokenEstimation struct {
	Tokens     int64   `json:"tokens"`
	IsEstimated bool   `json:"is_estimated"`
	Method     string  `json:"method"` // "exact", "char_estimation", "fallback"
	Confidence float64 `json:"confidence"` // 0.0-1.0
}

// ContextUtilization represents context usage metrics
type ContextUtilization struct {
	TokensUsed              int64   `json:"tokens_used"`
	ContextCapacity         int64   `json:"context_capacity"`
	UtilizationPercentage   float64 `json:"utilization_percentage"`
	EstimatedTokensRemaining int64  `json:"estimated_tokens_remaining"`
	IsEstimated             bool    `json:"is_estimated"`
	ModelName               string  `json:"model_name"`
	ModelFamily             string  `json:"model_family"`
	LastTokenCount          int64   `json:"last_token_count"`
	PressureLevel           string  `json:"pressure_level"` // "safe", "caution", "warning", "critical"
}

// NewCapacityManager creates a new capacity manager
func NewCapacityManager(configPath string) (*CapacityManager, error) {
	cm := &CapacityManager{
		configPath: configPath,
	}

	if err := cm.LoadConfig(); err != nil {
		return nil, fmt.Errorf("failed to load initial config: %w", err)
	}

	return cm, nil
}

// LoadConfig loads or reloads the model capacity configuration
func (cm *CapacityManager) LoadConfig() error {
	cm.mu.Lock()
	defer cm.mu.Unlock()

	// Check if file has been modified since last load
	info, err := os.Stat(cm.configPath)
	if err != nil {
		return fmt.Errorf("config file not found: %w", err)
	}

	if !cm.lastModified.IsZero() && !info.ModTime().After(cm.lastModified) {
		// File hasn't changed, no need to reload
		return nil
	}

	file, err := os.Open(cm.configPath)
	if err != nil {
		return fmt.Errorf("failed to open config file: %w", err)
	}
	defer file.Close()

	data, err := io.ReadAll(file)
	if err != nil {
		return fmt.Errorf("failed to read config file: %w", err)
	}

	var config CapacityConfig
	if err := json.Unmarshal(data, &config); err != nil {
		return fmt.Errorf("failed to parse config file: %w", err)
	}

	cm.config = &config
	cm.lastModified = info.ModTime()

	return nil
}

// GetModelCapacity retrieves capacity info for a specific model
func (cm *CapacityManager) GetModelCapacity(modelName string) ModelCapacity {
	// Try to reload config if it's been modified (this needs write lock)
	cm.LoadConfig()

	cm.mu.RLock()
	defer cm.mu.RUnlock()

	// Direct model lookup
	if capacity, exists := cm.config.Models[modelName]; exists {
		return capacity
	}

	// Try fuzzy matching for common variations
	modelLower := strings.ToLower(modelName)

	// Handle specific pattern matches first
	if strings.Contains(modelLower, "opus") && strings.Contains(modelLower, "4") {
		if capacity, exists := cm.config.Models["claude-4.1-opus"]; exists {
			capacity.DisplayName = fmt.Sprintf("%s (matched: claude-4.1-opus)", modelName)
			return capacity
		}
	}

	if strings.Contains(modelLower, "sonnet") && strings.Contains(modelLower, "4") {
		if capacity, exists := cm.config.Models["claude-4-sonnet"]; exists {
			capacity.DisplayName = fmt.Sprintf("%s (matched: claude-4-sonnet)", modelName)
			return capacity
		}
	}

	if strings.Contains(modelLower, "3.5") && strings.Contains(modelLower, "sonnet") {
		if capacity, exists := cm.config.Models["claude-3.5-sonnet"]; exists {
			capacity.DisplayName = fmt.Sprintf("%s (matched: claude-3.5-sonnet)", modelName)
			return capacity
		}
	}

	// Try family-based lookup
	for family, defaultCapacity := range cm.config.FamilyDefaults {
		if strings.Contains(strings.ToLower(modelName), strings.ToLower(family)) {
			// Create a capacity based on family defaults
			capacity := defaultCapacity
			capacity.DisplayName = fmt.Sprintf("%s (family: %s)", modelName, family)
			capacity.Family = family
			return capacity
		}
	}

	// Fallback to default capacity
	fallback := cm.config.Fallback
	fallback.DisplayName = fmt.Sprintf("%s (unknown)", modelName)
	fallback.Family = "unknown"
	return fallback
}

// EstimateTokensFromContent estimates token count from text content
func (cm *CapacityManager) EstimateTokensFromContent(content string, modelName string) TokenEstimation {
	capacity := cm.GetModelCapacity(modelName)

	if capacity.CharToTokenRatio == 0 {
		capacity.CharToTokenRatio = cm.config.Fallback.CharToTokenRatio
	}

	tokens := int64(float64(len(content)) / capacity.CharToTokenRatio)

	// Confidence based on known model vs fallback
	confidence := 0.8
	if capacity.Family == "unknown" {
		confidence = 0.5
	}

	return TokenEstimation{
		Tokens:     tokens,
		IsEstimated: true,
		Method:     "char_estimation",
		Confidence: confidence,
	}
}

// CalculateContextUtilization computes context utilization metrics
func (cm *CapacityManager) CalculateContextUtilization(tokensUsed int64, modelName string, isEstimated bool) ContextUtilization {
	capacity := cm.GetModelCapacity(modelName)

	utilizationPercentage := (float64(tokensUsed) / float64(capacity.ContextWindow)) * 100
	remainingTokens := capacity.ContextWindow - tokensUsed

	// Determine pressure level
	pressureLevel := "safe"
	if utilizationPercentage >= 96 {
		pressureLevel = "critical"
	} else if utilizationPercentage >= 81 {
		pressureLevel = "warning"
	} else if utilizationPercentage >= 51 {
		pressureLevel = "caution"
	}

	return ContextUtilization{
		TokensUsed:              tokensUsed,
		ContextCapacity:         capacity.ContextWindow,
		UtilizationPercentage:   utilizationPercentage,
		EstimatedTokensRemaining: remainingTokens,
		IsEstimated:             isEstimated,
		ModelName:               modelName,
		ModelFamily:             capacity.Family,
		LastTokenCount:          tokensUsed,
		PressureLevel:           pressureLevel,
	}
}

// EstimateCostUSD calculates the estimated cost in USD from token breakdowns.
// Returns 0 when pricing data is unavailable for the model.
func (cm *CapacityManager) EstimateCostUSD(modelName string, inputTokens, outputTokens, cacheReadTokens, cacheCreationTokens int64) float64 {
	cap := cm.GetModelCapacity(modelName)
	if cap.Pricing == nil {
		return 0
	}
	p := cap.Pricing
	cost := float64(inputTokens)*p.InputPerMTok +
		float64(outputTokens)*p.OutputPerMTok +
		float64(cacheReadTokens)*p.CacheReadPerMTok +
		float64(cacheCreationTokens)*p.CacheCreationPerMTok
	return cost / 1_000_000
}

// FormatTokenCount returns human-readable token count
func FormatTokenCount(tokens int64) string {
	if tokens < 1000 {
		return fmt.Sprintf("%d", tokens)
	} else if tokens < 1000000 {
		return fmt.Sprintf("%.1fK", float64(tokens)/1000)
	} else {
		return fmt.Sprintf("%.1fM", float64(tokens)/1000000)
	}
}

// FormatUtilizationPercentage returns formatted percentage string
func FormatUtilizationPercentage(percentage float64) string {
	return fmt.Sprintf("%.1f%%", percentage)
}

// GetPressureLevelIcon returns an appropriate icon for pressure level
func GetPressureLevelIcon(level string) string {
	switch level {
	case "safe":
		return "🟢"
	case "caution":
		return "🟡"
	case "warning":
		return "🔴"
	case "critical":
		return "⚠️"
	default:
		return "❓"
	}
}

package tailer

import (
	"bufio"
	"encoding/json"
	"fmt"
	"io"
	"os"
	"path/filepath"
	"strings"
	"time"

	"irrlicht/core/pkg/capacity"
)

// MessageEvent represents a single message event from transcript
type MessageEvent struct {
	Timestamp time.Time `json:"timestamp"`
	EventType string    `json:"event_type"`
	Content   string    `json:"content,omitempty"`
}

// SessionMetrics holds computed performance metrics
type SessionMetrics struct {
	MessagesPerMinute   float64        `json:"messages_per_minute"`
	ElapsedSeconds      int64          `json:"elapsed_seconds"`
	LastMessageAt       time.Time      `json:"last_message_at"`
	MessageHistory      []MessageEvent `json:"-"` // Sliding window, not serialized
	SessionStartAt      time.Time      `json:"session_start_at"`
	TotalTokens         int64          `json:"total_tokens,omitempty"`
	InputTokens         int64          `json:"input_tokens,omitempty"`
	OutputTokens        int64          `json:"output_tokens,omitempty"`
	CacheReadTokens     int64          `json:"cache_read_tokens,omitempty"`
	CacheCreationTokens int64          `json:"cache_creation_tokens,omitempty"`
	EstimatedCostUSD    float64        `json:"estimated_cost_usd,omitempty"`
	ModelName           string         `json:"model_name,omitempty"`
	ContextWindow       int64          `json:"context_window,omitempty"`
	ContextUtilization  float64        `json:"context_utilization_percentage,omitempty"`
	PressureLevel       string         `json:"pressure_level,omitempty"` // "safe", "caution", "warning", "critical"

	// Raw event data for real-time client-side calculations
	TotalEventCount        int64     `json:"total_event_count,omitempty"`
	RecentEventCount       int64     `json:"recent_event_count,omitempty"`
	RecentEventWindowStart time.Time `json:"recent_event_window_start,omitempty"`

	// Tool call tracking — count unmatched tool_use/tool_result pairs
	HasOpenToolCall   bool `json:"has_open_tool_call"`
	OpenToolCallCount int  `json:"open_tool_call_count,omitempty"`

	// LastEventType is the event type of the most recent message event in
	// the transcript (e.g. "assistant", "user", "tool_use", "tool_result").
	// Used for content-based working/waiting detection.
	LastEventType string `json:"last_event_type,omitempty"`

	// LastOpenToolNames holds the tool names from the most recent assistant
	// message that called tools. Cleared when a user message appears.
	// Used to detect user-blocking tools (AskUserQuestion, ExitPlanMode).
	LastOpenToolNames []string `json:"last_open_tool_names,omitempty"`

	// LastToolResultWasError is true when the most recently processed
	// tool_result content block had is_error=true (user rejection / ESC).
	LastToolResultWasError bool `json:"last_tool_result_was_error"`

	// LastCWD is the most recent working directory seen in the transcript.
	// Extracted during parsing so callers don't need a separate file read.
	LastCWD string `json:"last_cwd,omitempty"`

	// LastAssistantText is the text content of the most recent assistant
	// message, truncated to ~200 characters.
	LastAssistantText string `json:"last_assistant_text,omitempty"`

	// PermissionMode is the session's permission mode (e.g. "default",
	// "plan", "bypassPermissions"). Extracted from "permission-mode" events.
	PermissionMode string `json:"permission_mode,omitempty"`
}

// TranscriptTailer monitors transcript files and computes metrics.
// Format-specific parsing is delegated to a TranscriptParser.
type TranscriptTailer struct {
	path        string
	lastOffset  int64
	metrics     *SessionMetrics
	windowSize  time.Duration // Default 60 seconds
	capacityMgr *capacity.CapacityManager

	// parser handles format-specific line parsing (Claude Code, Codex, Pi).
	parser TranscriptParser

	// adapter name for model config fallback.
	adapter string

	// Context window override from transcript or extended context model suffix.
	contextWindowOverride int64

	// Tool call pairing counters — accumulated from ParsedEvent deltas.
	toolUseCount    int
	toolResultCount int

	// lastOpenToolNames holds tool names from open tool calls.
	lastOpenToolNames []string

	// contentChars accumulates character count from message content for
	// token estimation when explicit token counts aren't available.
	contentChars int64

	// Token breakdown accumulators (latest snapshot, not cumulative).
	inputTokens         int64
	outputTokens        int64
	cacheReadTokens     int64
	cacheCreationTokens int64

	// lastToolResultWasError tracks is_error on the most recent tool_result.
	lastToolResultWasError bool

	// lastCWD tracks the most recent working directory seen in transcript lines.
	lastCWD string

	// lastAssistantText holds the text content of the most recent assistant
	// message, truncated to ~200 characters.
	lastAssistantText string
}

// NewTranscriptTailer creates a new tailer for the given transcript path.
// The parser handles format-specific line parsing; adapter is used for model
// config fallback.
func NewTranscriptTailer(path string, parser TranscriptParser, adapter string) *TranscriptTailer {
	return &TranscriptTailer{
		path:        path,
		lastOffset:  0,
		capacityMgr: capacity.DefaultCapacityManager(),
		parser:      parser,
		adapter:     adapter,
		metrics: &SessionMetrics{
			MessageHistory: make([]MessageEvent, 0),
			SessionStartAt: time.Time{},
		},
		windowSize: 60 * time.Second,
	}
}

// SetSessionStartTime allows preserving the session start time across multiple invocations
func (t *TranscriptTailer) SetSessionStartTime(startTime time.Time) {
	if t.metrics != nil {
		t.metrics.SessionStartAt = startTime
	}
}

// TailAndProcess reads the last ~64KB of transcript and processes new entries
func (t *TranscriptTailer) TailAndProcess() (*SessionMetrics, error) {
	file, err := os.Open(t.path)
	if err != nil {
		return nil, fmt.Errorf("failed to open transcript: %w", err)
	}
	defer file.Close()

	stat, err := file.Stat()
	if err != nil {
		return nil, fmt.Errorf("failed to stat transcript: %w", err)
	}
	fileSize := stat.Size()

	const maxTailSize = 64 * 1024
	startPos := int64(0)
	switch {
	case fileSize < t.lastOffset:
		// File rotated/truncated.
		startPos = 0
	case t.lastOffset > 0:
		// Normal incremental path: never skip ahead of the last processed byte.
		startPos = t.lastOffset
	case fileSize > maxTailSize:
		// Initial read for large files: only tail the latest window.
		startPos = fileSize - maxTailSize
	}

	_, err = file.Seek(startPos, io.SeekStart)
	if err != nil {
		return nil, fmt.Errorf("failed to seek transcript: %w", err)
	}

	currentOffset := startPos
	var reader io.Reader = file

	// On the initial truncated read of a large file, we may start in the
	// middle of a JSON line. If so, discard the partial line to align scanner
	// to a full JSONL entry boundary.
	if t.lastOffset == 0 && startPos > 0 {
		prev := []byte{0}
		if _, err := file.ReadAt(prev, startPos-1); err == nil && prev[0] != '\n' {
			br := bufio.NewReader(file)
			if discarded, err := br.ReadString('\n'); err == nil {
				currentOffset += int64(len(discarded))
			} else {
				return nil, fmt.Errorf("failed to align transcript boundary: %w", err)
			}
			reader = br
		}
	}

	scanner := bufio.NewScanner(reader)
	// Large tool results (especially from Pi/Codex read/bash output) can exceed
	// bufio.Scanner's 64KB default token size.
	scanner.Buffer(make([]byte, 64*1024), 2*1024*1024)

	for scanner.Scan() {
		line := strings.TrimSpace(scanner.Text())
		currentOffset += int64(len(scanner.Bytes()) + 1)

		if line == "" {
			continue
		}

		// Quick JSON check.
		if !strings.HasPrefix(line, "{") || !strings.HasSuffix(line, "}") {
			continue
		}

		var raw map[string]interface{}
		if err := json.Unmarshal([]byte(line), &raw); err != nil {
			continue
		}

		// Delegate to format-specific parser.
		parsed := t.parser.ParseLine(raw)
		if parsed == nil || parsed.Skip {
			// Even for skipped events, apply metadata that the parser extracted
			// (e.g. model from model_change, CWD from session header).
			if parsed != nil {
				t.applyMetadata(parsed)
			}
			continue
		}

		// Apply tool tracking deltas from the parser.
		t.toolUseCount += len(parsed.ToolUseNames)
		t.lastOpenToolNames = append(t.lastOpenToolNames, parsed.ToolUseNames...)
		t.toolResultCount += parsed.ToolResultCount
		for i := 0; i < parsed.ToolResultCount; i++ {
			if len(t.lastOpenToolNames) > 0 {
				t.lastOpenToolNames = t.lastOpenToolNames[1:]
			}
		}
		if parsed.ClearToolNames && parsed.ToolResultCount == 0 {
			t.lastOpenToolNames = nil
		}
		if parsed.IsError {
			t.lastToolResultWasError = true
		} else if parsed.ToolResultCount > 0 {
			t.lastToolResultWasError = false
		}

		// Apply metadata.
		t.applyMetadata(parsed)

		// Track assistant text.
		if parsed.AssistantText != "" {
			t.lastAssistantText = parsed.AssistantText
		}
		if parsed.ClearToolNames {
			t.lastAssistantText = ""
		}

		// Accumulate content chars.
		t.contentChars += parsed.ContentChars

		t.addMessageEvent(MessageEvent{
			Timestamp: parsed.Timestamp,
			EventType: parsed.EventType,
		})
	}

	t.lastOffset = currentOffset

	// Compute current metrics.
	t.computeMetrics()

	// Model config fallback.
	if t.metrics.ModelName == "" {
		if defaultModel := getDefaultModelFromConfig(t.adapter); defaultModel != "" {
			t.metrics.ModelName = defaultModel
		}
	}

	// Estimate tokens from content chars when no explicit token data exists.
	if t.metrics.TotalTokens == 0 && t.contentChars > 0 && t.capacityMgr != nil && t.metrics.ModelName != "" {
		cap := t.capacityMgr.GetModelCapacity(t.metrics.ModelName)
		ratio := cap.CharToTokenRatio
		if ratio <= 0 {
			ratio = 4.0
		}
		t.metrics.TotalTokens = int64(float64(t.contentChars) / ratio)
		if t.inputTokens == 0 && t.outputTokens == 0 {
			t.inputTokens = t.metrics.TotalTokens * 9 / 10
			t.outputTokens = t.metrics.TotalTokens - t.inputTokens
		}
	}

	// Recompute cost if token estimation filled in the breakdown.
	if t.metrics.EstimatedCostUSD == 0 && t.inputTokens > 0 && t.capacityMgr != nil && t.metrics.ModelName != "" {
		t.metrics.InputTokens = t.inputTokens
		t.metrics.OutputTokens = t.outputTokens
		t.metrics.EstimatedCostUSD = t.capacityMgr.EstimateCostUSD(
			t.metrics.ModelName, t.inputTokens, t.outputTokens, t.cacheReadTokens, t.cacheCreationTokens)
	}

	t.computeContextUtilization()

	return t.metrics, scanner.Err()
}

// applyMetadata applies model/token/CWD/permission metadata from a parsed event.
func (t *TranscriptTailer) applyMetadata(parsed *ParsedEvent) {
	if parsed.ModelName != "" {
		if strings.Contains(parsed.ModelName, "[1m]") {
			t.contextWindowOverride = 1000000
		}
		t.metrics.ModelName = NormalizeModelName(parsed.ModelName)
	}
	if parsed.ContextWindow > 0 {
		t.contextWindowOverride = parsed.ContextWindow
	}
	if parsed.Tokens != nil {
		if parsed.Tokens.Total > 0 {
			t.metrics.TotalTokens = parsed.Tokens.Total
		}
		if parsed.Tokens.Input > 0 || parsed.Tokens.Output > 0 {
			t.inputTokens = parsed.Tokens.Input
			t.outputTokens = parsed.Tokens.Output
			t.cacheReadTokens = parsed.Tokens.CacheRead
			t.cacheCreationTokens = parsed.Tokens.CacheCreation
		}
	}
	if parsed.CWD != "" {
		t.lastCWD = parsed.CWD
	}
	if parsed.PermissionMode != "" {
		t.metrics.PermissionMode = parsed.PermissionMode
	}
}

// addMessageEvent adds a new message event and maintains sliding window.
// Tool call counting is NOT done here — it's handled from ParsedEvent deltas
// in TailAndProcess to avoid double-counting.
func (t *TranscriptTailer) addMessageEvent(event MessageEvent) {
	t.metrics.MessageHistory = append(t.metrics.MessageHistory, event)
	t.metrics.LastMessageAt = event.Timestamp
	t.metrics.LastEventType = event.EventType

	if t.metrics.SessionStartAt.IsZero() || event.Timestamp.Before(t.metrics.SessionStartAt) {
		t.metrics.SessionStartAt = event.Timestamp
	}
}

// computeMetrics calculates messages per minute and elapsed time
func (t *TranscriptTailer) computeMetrics() {
	if len(t.metrics.MessageHistory) == 0 {
		t.metrics.MessagesPerMinute = 0
		t.metrics.ElapsedSeconds = 0
		t.metrics.TotalEventCount = 0
		t.metrics.RecentEventCount = 0
		t.metrics.RecentEventWindowStart = time.Time{}
		return
	}

	currentTime := time.Now()
	latestTime := t.metrics.LastMessageAt
	if latestTime.IsZero() {
		latestTime = currentTime
	}

	if !t.metrics.SessionStartAt.IsZero() {
		t.metrics.ElapsedSeconds = int64(latestTime.Sub(t.metrics.SessionStartAt).Seconds())
	}

	t.metrics.TotalEventCount = int64(len(t.metrics.MessageHistory))

	fiveMinutesAgo := currentTime.Add(-5 * time.Minute)
	windowStart := fiveMinutesAgo
	if t.metrics.SessionStartAt.After(fiveMinutesAgo) {
		windowStart = t.metrics.SessionStartAt
	}
	t.metrics.RecentEventWindowStart = windowStart

	recentEventCount := int64(0)
	for _, msg := range t.metrics.MessageHistory {
		if msg.Timestamp.After(windowStart) || msg.Timestamp.Equal(windowStart) {
			recentEventCount++
		}
	}
	t.metrics.RecentEventCount = recentEventCount

	// Compute open tool call count from pairing counters.
	openCalls := t.toolUseCount - t.toolResultCount
	if openCalls < 0 {
		openCalls = 0
	}
	t.metrics.OpenToolCallCount = openCalls
	t.metrics.HasOpenToolCall = openCalls > 0
	t.metrics.LastOpenToolNames = t.lastOpenToolNames
	t.metrics.LastToolResultWasError = t.lastToolResultWasError
	t.metrics.LastCWD = t.lastCWD
	t.metrics.LastAssistantText = t.lastAssistantText

	// Token breakdown + estimated cost.
	t.metrics.InputTokens = t.inputTokens
	t.metrics.OutputTokens = t.outputTokens
	t.metrics.CacheReadTokens = t.cacheReadTokens
	t.metrics.CacheCreationTokens = t.cacheCreationTokens
	if t.capacityMgr != nil && t.metrics.ModelName != "" {
		t.metrics.EstimatedCostUSD = t.capacityMgr.EstimateCostUSD(
			t.metrics.ModelName, t.inputTokens, t.outputTokens, t.cacheReadTokens, t.cacheCreationTokens)
	}

	// Sliding window for messages per minute.
	legacyWindowStart := latestTime.Add(-t.windowSize)
	messageCount := 0
	filteredHistory := make([]MessageEvent, 0, len(t.metrics.MessageHistory))
	for _, msg := range t.metrics.MessageHistory {
		if msg.Timestamp.After(legacyWindowStart) || msg.Timestamp.Equal(legacyWindowStart) {
			filteredHistory = append(filteredHistory, msg)
			messageCount++
		}
	}
	t.metrics.MessageHistory = filteredHistory

	if messageCount > 0 {
		if len(filteredHistory) > 1 {
			timeSpan := latestTime.Sub(filteredHistory[0].Timestamp)
			if timeSpan > 0 {
				t.metrics.MessagesPerMinute = float64(messageCount) / timeSpan.Minutes()
			} else {
				t.metrics.MessagesPerMinute = float64(messageCount)
			}
		} else {
			t.metrics.MessagesPerMinute = float64(messageCount) / t.windowSize.Minutes()
		}
	} else {
		t.metrics.MessagesPerMinute = 0
	}
}

// GetMetrics returns current computed metrics
func (t *TranscriptTailer) GetMetrics() *SessionMetrics {
	if t.metrics == nil {
		return &SessionMetrics{}
	}
	return t.metrics
}

// ResetOffset resets the file offset (useful for testing or file rotation)
func (t *TranscriptTailer) ResetOffset() {
	t.lastOffset = 0
}

// computeContextUtilization calculates context utilization percentage and pressure level.
func (t *TranscriptTailer) computeContextUtilization() {
	if t.metrics.TotalTokens == 0 || t.metrics.ModelName == "" {
		t.metrics.ContextUtilization = 0.0
		t.metrics.PressureLevel = "unknown"
		return
	}

	var effectiveContextWindow int64

	if t.contextWindowOverride > 0 {
		effectiveContextWindow = t.contextWindowOverride
	}

	if effectiveContextWindow <= 0 && t.capacityMgr != nil {
		cap := t.capacityMgr.GetModelCapacity(t.metrics.ModelName)
		if ctx1m, ok := cap.BetaFeatures["context_1m"]; ok && ctx1m > 0 {
			effectiveContextWindow = ctx1m
		} else if cap.ContextWindow > 0 {
			effectiveContextWindow = cap.ContextWindow
		}
	}

	if effectiveContextWindow <= 0 {
		effectiveContextWindow = int64(200000)
	}

	utilizationPercentage := (float64(t.metrics.TotalTokens) / float64(effectiveContextWindow)) * 100

	pressureLevel := "safe"
	if utilizationPercentage >= 90 {
		pressureLevel = "critical"
	} else if utilizationPercentage >= 80 {
		pressureLevel = "warning"
	} else if utilizationPercentage >= 60 {
		pressureLevel = "caution"
	}

	t.metrics.ContextWindow = effectiveContextWindow
	t.metrics.ContextUtilization = utilizationPercentage
	t.metrics.PressureLevel = pressureLevel
}

// --- Model config fallback ---

// getDefaultModelFromConfig reads the default model from the appropriate config
// based on adapter name.
func getDefaultModelFromConfig(adapter string) string {
	homeDir, err := os.UserHomeDir()
	if err != nil {
		return ""
	}
	switch adapter {
	case "pi":
		return getPiModel(homeDir)
	case "codex":
		return getCodexModel(homeDir)
	default:
		return getClaudeModel(homeDir)
	}
}

func getClaudeModel(homeDir string) string {
	data, err := os.ReadFile(filepath.Join(homeDir, ".claude", "settings.json"))
	if err != nil {
		return ""
	}
	var settings map[string]interface{}
	if err := json.Unmarshal(data, &settings); err != nil {
		return ""
	}
	if model, ok := settings["model"].(string); ok {
		return NormalizeModelName(model)
	}
	return ""
}

func getCodexModel(homeDir string) string {
	data, err := os.ReadFile(filepath.Join(homeDir, ".codex", "config.toml"))
	if err != nil {
		return ""
	}
	for _, line := range strings.Split(string(data), "\n") {
		line = strings.TrimSpace(line)
		if strings.HasPrefix(line, "model") && strings.Contains(line, "=") {
			parts := strings.SplitN(line, "=", 2)
			if strings.TrimSpace(parts[0]) == "model" {
				model := strings.Trim(strings.TrimSpace(parts[1]), "\"'")
				if model != "" {
					return model
				}
			}
		}
	}
	return ""
}

func getPiModel(homeDir string) string {
	data, err := os.ReadFile(filepath.Join(homeDir, ".pi", "agent", "settings.json"))
	if err != nil {
		return ""
	}
	var settings map[string]interface{}
	if err := json.Unmarshal(data, &settings); err != nil {
		return ""
	}
	if model, ok := settings["defaultModel"].(string); ok {
		return NormalizeModelName(model)
	}
	return ""
}

package codex

import (
	"irrlicht/core/pkg/tailer"
	"irrlicht/core/pkg/transcript"
)

// Parser implements tailer.TranscriptParser for OpenAI Codex transcripts.
// Codex uses top-level "role" fields on "message" events and separate
// "function_call" / "function_call_output" events for tool calls.
type Parser struct{}

// ParseLine parses a Codex JSONL line into a normalized ParsedEvent.
func (p *Parser) ParseLine(raw map[string]interface{}) *tailer.ParsedEvent {
	ev := &tailer.ParsedEvent{
		Timestamp: tailer.ParseTimestamp(raw),
	}

	eventType := ""
	if et, ok := raw["type"].(string); ok {
		eventType = et
	}

	// Session header: {"id": "...", "timestamp": "..."} — no type field.
	if eventType == "" {
		ev.Skip = true
		return ev
	}

	// State records: {"record_type": "state"} — skip.
	if _, ok := raw["record_type"]; ok && eventType != "message" {
		ev.Skip = true
		return ev
	}

	// Reasoning events — skip but extract nothing.
	if eventType == "reasoning" {
		ev.Skip = true
		return ev
	}

	ev.CWD = transcript.ExtractCWDFromLine(raw)

	// Model/token extraction from payload-wrapped events.
	ev.ModelName, ev.ContextWindow, ev.Tokens = extractCodexMetadata(raw)

	// Content character count.
	ev.ContentChars = extractCodexContentChars(raw)

	// Map event types to normalized forms.
	switch eventType {
	case "message":
		if !parseCodexMessage(raw, ev) {
			ev.Skip = true
			return ev
		}

	case "response_item":
		if payload, ok := raw["payload"].(map[string]interface{}); ok {
			if !parseCodexResponseItem(payload, ev) {
				ev.Skip = true
				return ev
			}
		} else {
			ev.Skip = true
			return ev
		}

	case "function_call":
		if !parseCodexFunctionCall(raw, ev) {
			ev.Skip = true
			return ev
		}

	case "function_call_output":
		parseCodexFunctionCallOutput(ev)

	case "session_meta", "event_msg", "turn_context":
		ev.Skip = true
		return ev

	default:
		ev.Skip = true
		return ev
	}

	return ev
}

func parseCodexMessage(raw map[string]interface{}, ev *tailer.ParsedEvent) bool {
	role, _ := raw["role"].(string)
	switch role {
	case "assistant":
		ev.EventType = "assistant_message"
		ev.AssistantText = tailer.ExtractAssistantText(raw)
	case "user", "developer":
		ev.EventType = "user_message"
		ev.ClearToolNames = true
	default:
		return false
	}
	return true
}

func parseCodexResponseItem(payload map[string]interface{}, ev *tailer.ParsedEvent) bool {
	payloadType, _ := payload["type"].(string)
	switch payloadType {
	case "message":
		return parseCodexMessage(payload, ev)
	case "function_call", "custom_tool_call":
		return parseCodexFunctionCall(payload, ev)
	case "function_call_output", "custom_tool_call_output":
		parseCodexFunctionCallOutput(ev)
		return true
	case "web_search_call":
		ev.EventType = "function_call_output"
		ev.ToolUseNames = []string{"web_search"}
		ev.ToolResultCount = 1
		return true
	default:
		return false
	}
}

func parseCodexFunctionCall(raw map[string]interface{}, ev *tailer.ParsedEvent) bool {
	name, _ := raw["name"].(string)
	ev.EventType = "function_call"
	if name != "" {
		ev.ToolUseNames = []string{name}
	}
	return true
}

func parseCodexFunctionCallOutput(ev *tailer.ParsedEvent) {
	ev.EventType = "function_call_output"
	ev.ToolResultCount = 1
}

func extractCodexContentChars(raw map[string]interface{}) int64 {
	if payload, ok := raw["payload"].(map[string]interface{}); ok {
		return extractCodexContentChars(payload)
	}
	chars := tailer.ExtractContentChars(raw)
	if message, ok := raw["message"].(string); ok {
		chars += int64(len(message))
	}
	return chars
}

// extractCodexMetadata extracts model, context window, and token info from Codex events.
func extractCodexMetadata(raw map[string]interface{}) (string, int64, *tailer.TokenSnapshot) {
	var modelName string
	var contextWindow int64
	var tokens *tailer.TokenSnapshot

	// Direct model field.
	if model, ok := raw["model"].(string); ok && model != "" {
		modelName = tailer.NormalizeModelName(model)
	}

	// Payload-wrapped events (event_msg, response_item, etc.).
	if payload, ok := raw["payload"].(map[string]interface{}); ok {
		if model, ok := payload["model"].(string); ok && model != "" {
			modelName = tailer.NormalizeModelName(model)
		}
		// Token info from payload.info.total_token_usage.
		if info, ok := payload["info"].(map[string]interface{}); ok {
			if usage, ok := info["total_token_usage"].(map[string]interface{}); ok {
				tokens = tailer.ExtractUsage(usage)
			}
			if cw, ok := info["model_context_window"].(float64); ok && cw > 0 {
				contextWindow = int64(cw)
			}
		}
		// model_context_window directly on payload (task_started).
		if cw, ok := payload["model_context_window"].(float64); ok && cw > 0 {
			contextWindow = int64(cw)
		}
		// Direct usage on payload.
		if tokens == nil {
			if usage, ok := payload["usage"].(map[string]interface{}); ok {
				tokens = tailer.ExtractUsage(usage)
			}
		}
	}

	// Message-level usage (Codex responses API format).
	if usage, ok := raw["usage"].(map[string]interface{}); ok {
		tokens = tailer.ExtractUsage(usage)
	}

	return modelName, contextWindow, tokens
}

// Package tailer provides transcript tailing and metrics computation.
// Format-specific parsing is delegated to TranscriptParser implementations
// that live in each agent adapter package.
package tailer

import (
	"regexp"
	"strings"
	"time"
)

// ParsedEvent is the normalized output from a format-specific transcript parser.
// Each parser maps its native event structure into these fields.
type ParsedEvent struct {
	EventType string    // normalized: "assistant_message", "user_message", "turn_done", etc.
	Timestamp time.Time // event timestamp
	Skip      bool      // true → ignore this line entirely

	// Tool tracking — parser reports deltas, tailer accumulates.
	ToolUseNames    []string // tool names from tool_use/toolCall blocks in this event
	ToolResultCount int      // number of tool_result blocks in this event
	IsError         bool     // true if the tool result had is_error=true
	ClearToolNames  bool     // true → reset lastOpenToolNames (on user messages)

	// Metadata extracted by the parser.
	ModelName      string
	ContextWindow  int64
	Tokens         *TokenSnapshot // nil = no token data in this event
	AssistantText  string         // ≤200 chars, for waiting-state display
	ContentChars   int64          // character count for token estimation
	CWD            string         // working directory if found
	PermissionMode string         // Claude Code only
}

// TokenSnapshot holds a token breakdown from a single event.
type TokenSnapshot struct {
	Input         int64
	Output        int64
	CacheRead     int64
	CacheCreation int64
	Total         int64
}

// TranscriptParser parses a single JSONL line from a specific transcript format
// and returns a normalized ParsedEvent. Implementations live in each agent
// adapter package (claudecode, codex, pi).
type TranscriptParser interface {
	// ParseLine parses a raw JSON map and returns a normalized event.
	// Returns nil for lines that should be silently ignored (no event emitted).
	ParseLine(raw map[string]interface{}) *ParsedEvent
}

// --- Shared helpers used by multiple parsers ---

// NormalizeModelName normalizes model names by removing date suffixes, extended
// context markers, and handling aliases. Exported for use by adapter parsers.
func NormalizeModelName(rawModel string) string {
	if rawModel == "" {
		return ""
	}

	// Strip extended context suffix (e.g. "claude-opus-4-6[1m]")
	rawModel = strings.TrimSuffix(rawModel, "[1m]")

	// Handle common aliases first
	aliases := map[string]string{
		"opusplan": "claude-opus-4-1",
		"sonnet":   "claude-sonnet-4-6",
		"haiku":    "claude-haiku-4-5",
	}
	if normalized, exists := aliases[rawModel]; exists {
		return normalized
	}

	// Remove date suffixes (e.g., "claude-opus-4-6-20250715" -> "claude-opus-4-6")
	datePattern := regexp.MustCompile(`-\d{8}$`)
	normalized := datePattern.ReplaceAllString(rawModel, "")

	// Match most-specific patterns first (longer model IDs before shorter)
	switch {
	case strings.Contains(normalized, "claude-opus-4-6"):
		return "claude-opus-4-6"
	case strings.Contains(normalized, "claude-sonnet-4-6"):
		return "claude-sonnet-4-6"
	case strings.Contains(normalized, "claude-sonnet-4-5"):
		return "claude-sonnet-4-5"
	case strings.Contains(normalized, "claude-haiku-4-5"):
		return "claude-haiku-4-5"
	case strings.Contains(normalized, "claude-opus-4-1"):
		return "claude-opus-4-1"
	case strings.Contains(normalized, "claude-sonnet-4"):
		return "claude-4-sonnet"
	case strings.Contains(normalized, "claude-3.5-sonnet"):
		return "claude-3.5-sonnet"
	case strings.Contains(normalized, "claude-3.5-haiku"):
		return "claude-3.5-haiku"
	}
	return normalized
}

// ExtractAssistantText extracts and concatenates text blocks from an assistant
// message, returning at most 200 characters. Checks both Claude Code
// (message.content[].text) and Codex (content[].text / content[].output_text) formats.
func ExtractAssistantText(raw map[string]interface{}) string {
	var parts []string

	collectText := func(arr []interface{}) {
		for _, item := range arr {
			if block, ok := item.(map[string]interface{}); ok {
				bt := block["type"]
				if bt == "text" || bt == "output_text" {
					if text, ok := block["text"].(string); ok && text != "" {
						parts = append(parts, text)
					}
				}
			}
		}
	}

	// Claude Code: message.content[]
	if msg, ok := raw["message"].(map[string]interface{}); ok {
		if arr, ok := msg["content"].([]interface{}); ok {
			collectText(arr)
		}
	}
	// Codex: top-level content[]
	if arr, ok := raw["content"].([]interface{}); ok {
		collectText(arr)
	}

	var text string
	switch len(parts) {
	case 0:
		return ""
	case 1:
		text = strings.TrimSpace(parts[0])
	default:
		text = strings.TrimSpace(strings.Join(parts, " "))
	}

	runes := []rune(text)
	if len(runes) > 200 {
		return string(runes[:200])
	}
	return text
}

// ExtractContentChars returns the total character count of text content in
// a transcript event, checking common content locations across formats.
func ExtractContentChars(raw map[string]interface{}) int64 {
	var chars int64
	addContentChars := func(arr []interface{}) {
		for _, item := range arr {
			if block, ok := item.(map[string]interface{}); ok {
				if text, ok := block["text"].(string); ok {
					chars += int64(len(text))
				}
			}
		}
	}
	// Top-level content array (Codex newer format)
	if arr, ok := raw["content"].([]interface{}); ok {
		addContentChars(arr)
	}
	// Nested message.content array (Claude Code format)
	if msg, ok := raw["message"].(map[string]interface{}); ok {
		if arr, ok := msg["content"].([]interface{}); ok {
			addContentChars(arr)
		}
	}
	// Codex function_call arguments
	if args, ok := raw["arguments"].(string); ok {
		chars += int64(len(args))
	}
	// Codex function_call_output
	if output, ok := raw["output"].(string); ok {
		chars += int64(len(output))
	}
	return chars
}

// ExtractUsage pulls token breakdown fields from a usage map.
// Handles both standard (Claude/Codex) and Pi field naming conventions.
func ExtractUsage(usage map[string]interface{}) *TokenSnapshot {
	snap := &TokenSnapshot{}
	hasBreakdown := false

	if v, ok := usage["input_tokens"].(float64); ok {
		snap.Input = int64(v)
		hasBreakdown = true
	}
	if v, ok := usage["output_tokens"].(float64); ok {
		snap.Output = int64(v)
		hasBreakdown = true
	}
	// Pi uses shorter field names as fallback.
	if !hasBreakdown {
		if v, ok := usage["input"].(float64); ok {
			snap.Input = int64(v)
			hasBreakdown = true
		}
		if v, ok := usage["output"].(float64); ok {
			snap.Output = int64(v)
			hasBreakdown = true
		}
	}
	// Standard cache field names.
	if v, ok := usage["cache_read_input_tokens"].(float64); ok {
		snap.CacheRead = int64(v)
	}
	if v, ok := usage["cache_creation_input_tokens"].(float64); ok {
		snap.CacheCreation = int64(v)
	}
	// Pi cache field names.
	if v, ok := usage["cacheRead"].(float64); ok {
		snap.CacheRead = int64(v)
	}
	if v, ok := usage["cacheWrite"].(float64); ok {
		snap.CacheCreation = int64(v)
	}
	snap.Total = snap.Input + snap.Output + snap.CacheRead + snap.CacheCreation
	// total_tokens override
	if total, ok := usage["total_tokens"].(float64); ok {
		snap.Total = int64(total)
	}
	// Pi totalTokens field.
	if total, ok := usage["totalTokens"].(float64); ok {
		snap.Total = int64(total)
	}

	if !hasBreakdown && snap.Total == 0 {
		return nil
	}
	return snap
}

// ParseTimestamp extracts a timestamp from a raw JSON map, trying RFC3339
// and millisecond-precision formats, then numeric Unix timestamps.
func ParseTimestamp(raw map[string]interface{}) time.Time {
	if ts, ok := raw["timestamp"]; ok {
		if tsStr, ok := ts.(string); ok {
			if parsed, err := time.Parse(time.RFC3339, tsStr); err == nil {
				return parsed
			}
			if parsed, err := time.Parse("2006-01-02T15:04:05.000Z", tsStr); err == nil {
				return parsed
			}
		} else if tsNum, ok := ts.(float64); ok && tsNum > 0 {
			return time.Unix(int64(tsNum), 0)
		}
	}
	return time.Now()
}

