	// claude-sonnet-4-5 has beta_features.context_1m → 1M effective window
	tests := []struct {
		name         string
		inputTokens  float64
		wantPressure string
	}{
		{"safe", 250000, "safe"},           // 25% of 1M
		{"caution", 650000, "caution"},     // 65% of 1M
		{"warning", 825000, "warning"},     // 82.5% of 1M
		{"critical", 925000, "critical"},   // 92.5% of 1M
